#' Magee Equation - Oncotype DX Estimator
#'
#' Implements the Magee Equations (Klein et al. 2013, PMID: 23503643) for
#' estimating Oncotype DX Recurrence Score from standard pathology variables.
#' Provides all four published equations (Original + 3 new) with risk
#' category classification and concordance analysis.
#' 
#'
#' @examples
#' \donttest{
#' mageeequation(data = data, nuclearGrade = nucgrade,
#'     mitosis = mitotic_score, erHscore = er_hscore,
#'     prHscore = pr_hscore, her2Status = her2)
#'}
#' @param data .
#' @param nuclearGrade .
#' @param mitosis .
#' @param erHscore .
#' @param prHscore .
#' @param her2Status .
#' @param her2Positive .
#' @param nottinghamScore .
#' @param tumorSize .
#' @param ki67 .
#' @param actualRS .
#' @param erFormat .
#' @param prFormat .
#' @param equations .
#' @param lowCutoff .
#' @param highCutoff .
#' @param showIndividual .
#' @param showConcordance .
#' @param showDistribution .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$todo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$equationInfo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$summaryTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$riskTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$concordanceTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$individualTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$distributionPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$concordancePlot} \tab \tab \tab \tab \tab an image \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$summaryTable$asDF}
#'
#' \code{as.data.frame(results$summaryTable)}
#'
#' @export
mageeequation <- function(
    data,
    nuclearGrade,
    mitosis,
    erHscore,
    prHscore,
    her2Status,
    her2Positive,
    nottinghamScore = NULL,
    tumorSize = NULL,
    ki67 = NULL,
    actualRS = NULL,
    erFormat = "hscore",
    prFormat = "hscore",
    equations = "all",
    lowCutoff = 15,
    highCutoff = 26,
    showIndividual = TRUE,
    showConcordance = TRUE,
    showDistribution = TRUE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("mageeequation requires jmvcore to be installed (restart may be required)")

    if ( ! missing(nuclearGrade)) nuclearGrade <- jmvcore::resolveQuo(jmvcore::enquo(nuclearGrade))
    if ( ! missing(mitosis)) mitosis <- jmvcore::resolveQuo(jmvcore::enquo(mitosis))
    if ( ! missing(erHscore)) erHscore <- jmvcore::resolveQuo(jmvcore::enquo(erHscore))
    if ( ! missing(prHscore)) prHscore <- jmvcore::resolveQuo(jmvcore::enquo(prHscore))
    if ( ! missing(her2Status)) her2Status <- jmvcore::resolveQuo(jmvcore::enquo(her2Status))
    if ( ! missing(nottinghamScore)) nottinghamScore <- jmvcore::resolveQuo(jmvcore::enquo(nottinghamScore))
    if ( ! missing(tumorSize)) tumorSize <- jmvcore::resolveQuo(jmvcore::enquo(tumorSize))
    if ( ! missing(ki67)) ki67 <- jmvcore::resolveQuo(jmvcore::enquo(ki67))
    if ( ! missing(actualRS)) actualRS <- jmvcore::resolveQuo(jmvcore::enquo(actualRS))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(nuclearGrade), nuclearGrade, NULL),
            `if`( ! missing(mitosis), mitosis, NULL),
            `if`( ! missing(erHscore), erHscore, NULL),
            `if`( ! missing(prHscore), prHscore, NULL),
            `if`( ! missing(her2Status), her2Status, NULL),
            `if`( ! missing(nottinghamScore), nottinghamScore, NULL),
            `if`( ! missing(tumorSize), tumorSize, NULL),
            `if`( ! missing(ki67), ki67, NULL),
            `if`( ! missing(actualRS), actualRS, NULL))


    options <- mageeequationOptions$new(
        nuclearGrade = nuclearGrade,
        mitosis = mitosis,
        erHscore = erHscore,
        prHscore = prHscore,
        her2Status = her2Status,
        her2Positive = her2Positive,
        nottinghamScore = nottinghamScore,
        tumorSize = tumorSize,
        ki67 = ki67,
        actualRS = actualRS,
        erFormat = erFormat,
        prFormat = prFormat,
        equations = equations,
        lowCutoff = lowCutoff,
        highCutoff = highCutoff,
        showIndividual = showIndividual,
        showConcordance = showConcordance,
        showDistribution = showDistribution)

    analysis <- mageeequationClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

